import React, { useState, useEffect } from 'react';
import api, { formatDate } from '../../utils/api';
import { useToast } from '../../context/ToastContext';

const ROLES = ['customer','warehouse','delivery','admin'];
const roleLabel = { customer: 'Khách hàng', warehouse: 'Kho hàng', delivery: 'Giao hàng', admin: 'Admin' };
const emptyForm = { fullName: '', email: '', password: '', phone: '', address: '', role: 'customer', status: 'active' };

export default function AdminUsersPage() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState(emptyForm);
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const { addToast } = useToast();

  useEffect(() => { loadUsers(); }, []);

  const loadUsers = async () => {
    try {
      const res = await api.get('/users');
      setUsers(res.data.users);
    } catch { addToast('Không thể tải dữ liệu', 'error'); }
    finally { setLoading(false); }
  };

  const openCreate = () => { setForm(emptyForm); setModal('create'); };
  const openEdit = (u) => {
    setForm({ fullName: u.fullName, email: u.email, password: '', phone: u.phone || '', address: u.address || '', role: u.role, status: u.status });
    setModal(u);
  };

  const save = async () => {
    try {
      const payload = { ...form };
      if (modal !== 'create' && !payload.password) delete payload.password;
      if (modal === 'create') {
        await api.post('/users', payload);
        addToast('Tạo tài khoản thành công!', 'success');
      } else {
        await api.put(`/users/${modal.userID}`, payload);
        addToast('Cập nhật thành công!', 'success');
      }
      setModal(null);
      loadUsers();
    } catch (err) { addToast(err.response?.data?.message || 'Lỗi', 'error'); }
  };

  const deactivate = async (id) => {
    if (!window.confirm('Vô hiệu hóa tài khoản này?')) return;
    try {
      await api.delete(`/users/${id}`);
      addToast('Đã vô hiệu hóa tài khoản', 'info');
      loadUsers();
    } catch { addToast('Lỗi', 'error'); }
  };

  const filtered = users.filter(u =>
    (u.fullName.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase())) &&
    (!roleFilter || u.role === roleFilter)
  );

  if (loading) return <div className="loading"><div className="spinner" /></div>;

  return (
    <div className="page">
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div><h1>👥 Quản lý người dùng</h1><p>{users.length} tài khoản</p></div>
        <button className="btn btn-primary" onClick={openCreate}>+ Thêm tài khoản</button>
      </div>

      <div className="filter-bar">
        <input className="form-control search-input" placeholder="🔍 Tìm theo tên hoặc email..." value={search} onChange={e => setSearch(e.target.value)} />
        <select className="form-control" style={{ width: 160 }} value={roleFilter} onChange={e => setRoleFilter(e.target.value)}>
          <option value="">Tất cả vai trò</option>
          {ROLES.map(r => <option key={r} value={r}>{roleLabel[r]}</option>)}
        </select>
      </div>

      <div className="card">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>Họ tên</th><th>Email</th><th>Điện thoại</th><th>Vai trò</th><th>Trạng thái</th><th>Ngày tạo</th><th>Hành động</th></tr>
            </thead>
            <tbody>
              {filtered.map(u => (
                <tr key={u.userID}>
                  <td style={{ fontWeight: 600 }}>{u.fullName}</td>
                  <td style={{ color: 'var(--text-muted)' }}>{u.email}</td>
                  <td style={{ color: 'var(--text-muted)' }}>{u.phone || '—'}</td>
                  <td>
                    <span style={{ padding: '3px 8px', borderRadius: 20, fontSize: 11, fontWeight: 600,
                      background: u.role === 'admin' ? 'rgba(255,107,107,0.2)' : u.role === 'customer' ? 'rgba(108,99,255,0.2)' : u.role === 'warehouse' ? 'rgba(67,233,123,0.2)' : 'rgba(56,178,255,0.2)',
                      color: u.role === 'admin' ? 'var(--danger)' : u.role === 'customer' ? 'var(--accent)' : u.role === 'warehouse' ? 'var(--success)' : 'var(--info)'
                    }}>
                      {roleLabel[u.role]}
                    </span>
                  </td>
                  <td><span className={`badge badge-${u.status}`}>{u.status === 'active' ? 'Hoạt động' : 'Vô hiệu'}</span></td>
                  <td style={{ color: 'var(--text-muted)', fontSize: 12 }}>{formatDate(u.createdAt)}</td>
                  <td style={{ display: 'flex', gap: 6 }}>
                    <button className="btn btn-secondary btn-sm" onClick={() => openEdit(u)}>✏️</button>
                    {u.status === 'active' && (
                      <button className="btn btn-danger btn-sm" onClick={() => deactivate(u.userID)}>🚫</button>
                    )}
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr><td colSpan={7} style={{ textAlign: 'center', color: 'var(--text-muted)', padding: 32 }}>Không tìm thấy tài khoản</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div className="modal-title">{modal === 'create' ? '+ Tạo tài khoản' : '✏️ Chỉnh sửa tài khoản'}</div>
              <button className="modal-close" onClick={() => setModal(null)}>×</button>
            </div>
            {[
              { key: 'fullName', label: 'Họ và tên', type: 'text' },
              { key: 'email', label: 'Email', type: 'email' },
              { key: 'password', label: modal === 'create' ? 'Mật khẩu' : 'Mật khẩu mới (để trống = không đổi)', type: 'password' },
              { key: 'phone', label: 'Điện thoại', type: 'tel' },
              { key: 'address', label: 'Địa chỉ', type: 'text' },
            ].map(f => (
              <div className="form-group" key={f.key}>
                <label className="form-label">{f.label}</label>
                <input className="form-control" type={f.type} value={form[f.key]} onChange={e => setForm(p => ({ ...p, [f.key]: e.target.value }))} />
              </div>
            ))}
            <div className="form-group">
              <label className="form-label">Vai trò</label>
              <select className="form-control" value={form.role} onChange={e => setForm(p => ({ ...p, role: e.target.value }))}>
                {ROLES.map(r => <option key={r} value={r}>{roleLabel[r]}</option>)}
              </select>
            </div>
            {modal !== 'create' && (
              <div className="form-group">
                <label className="form-label">Trạng thái</label>
                <select className="form-control" value={form.status} onChange={e => setForm(p => ({ ...p, status: e.target.value }))}>
                  <option value="active">Hoạt động</option>
                  <option value="inactive">Vô hiệu</option>
                </select>
              </div>
            )}
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={save}>{modal === 'create' ? '+ Tạo' : '💾 Lưu'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
